import { useState } from 'react';
import './App.css';

function App() {
  const [isDarkMode, setIsDarkMode] = useState(false);

  const toggleTheme = () => {
    setIsDarkMode((prevMode) => !prevMode);
  };

  return (
    <div className={`app ${isDarkMode ? 'dark' : 'light'}`}>
      <div className="page-shell">
        <header className="navbar">
          <nav>
            <ul className="nav-tabs">
              <li><button type="button">Projects</button></li>
              <li><button type="button">About Me</button></li>
              <li><button type="button">Contact</button></li>
            </ul>
          </nav>
          <button
            className="theme-toggle"
            onClick={toggleTheme}
            aria-label={`Switch to ${isDarkMode ? 'light' : 'dark'} mode`}
            title={`Switch to ${isDarkMode ? 'light' : 'dark'} mode`}
          >
            {isDarkMode ? '☀️' : '🌙'}
          </button>
        </header>

        <main className="container">
        <h1>About Me</h1>
        <p>
          Hi, I&apos;m a computer science student who enjoys building practical projects
          with React and learning new web technologies.
        </p>
        <p>
          I like solving coding problems, collaborating on team projects, and turning
          ideas into clean, user-friendly interfaces.
        </p>
        </main>
      </div>
    </div>
  );
}

export default App;
